starter.javascript:
// define charge(price, quantity):
//   if quantity === 0: return 0   (this exits immediately)
//   otherwise return price * quantity
// print charge(5, 0) and charge(5, 3) on one line separated by a space

reference.pseudocode:
PROCEDURE charge(price, quantity)
{
    IF(quantity = 0)
    {
        RETURN(0)
    }
    RETURN(price * quantity)
}
DISPLAY(charge(5, 0))
DISPLAY(charge(5, 3))

reference.python:
def charge(price, quantity):
    if quantity == 0:
        return 0
    return price * quantity

print(charge(5, 0), charge(5, 3))

reference.javascript:
function charge(price, quantity) {
  if (quantity === 0) {
    return 0;
  }
  return price * quantity;
}
console.log(charge(5, 0) + " " + charge(5, 3));

starter.javascript:
// define discountedPrice(price, discount):
//   if discount >= price: return 0   (early guard, never go negative)
//   otherwise return price - discount
// print discountedPrice(20, 5) and discountedPrice(20, 25) on one line

reference.pseudocode:
PROCEDURE discountedPrice(price, discount)
{
    IF(discount ≥ price)
    {
        RETURN(0)
    }
    RETURN(price - discount)
}
DISPLAY(discountedPrice(20, 5))
DISPLAY(discountedPrice(20, 25))

reference.python:
def discountedPrice(price, discount):
    if discount >= price:
        return 0
    return price - discount

print(discountedPrice(20, 5), discountedPrice(20, 25))

reference.javascript:
function discountedPrice(price, discount) {
